    return temp;
}

void traverse(struct BTreeNode *root){
    if(root==NULL)
        return;

    int i;

    for(i=0;i<root->n;i++){
        if(!root->leaf)
            traverse(root->child[i]);

        printf("%d ",root->keys[i]);
