}

struct BTreeNode* search(struct BTreeNode *root,int key){
    int i=0;

    while(i<root->n && key>root->keys[i])
        i++;

    if(i<root->n && key==root->keys[i])
        return root;

    if(root->leaf)
        return NULL;

    return search(root->child[i],key);
}

void splitChild(struct BTreeNode *parent,int index){
    struct BTreeNode *fullNode=parent->child[index];
    struct BTreeNode *newNode=createNode(fullNode->leaf);

    int mid=(M-1)/2;

    newNode->n=mid;

    for(int i=0;i<mid;i++)
        newNode->keys[i]=fullNode->keys[i+mid+1];

