    heap[size].burst = burst;
    heap[size].priority = priority;

    heapifyUp(size);

    size++;
}

Process dequeue()
{
    Process highestPriority = heap[0];

    heap[0] = heap[size - 1];

    size--;

    heapifyDown(0);

    return highestPriority;
}

