    int i;
    if (n->start != -1) {
        for (i = n->start; i <= *(n->end) && pattern[idx] != '\0'; i++, idx++) {
            if (text[i] != pattern[idx]) return -1;
        }
        if (pattern[idx] == '\0') return 1;
    }
    for (i = 0; i < MAX_CHAR; i++) {
        if (n->children[i] != NULL) {
            int res = doTraversal(n->children[i], pattern, idx);
            if (res == 1) return 1;
        }
    }
    return -1;
}

void searchPattern(const char* pattern) {
    int res = doTraversal(root, pattern, 0);
    if (res == 1)
        printf("Pattern '%s' found!\n", pattern);
    else
        printf("Pattern '%s' not found!\n", pattern);
}

int main() {
