void insertSuffix(Node* root, char* suffix)
{
    Node* curr = root;

    for(int i = 0; suffix[i] != '\0'; i++)
    {
        int indx = suffix[i] - 'a';

        if(curr->children[indx] == NULL)
        {
            curr->children[indx] = createNode();
        }

        curr = curr->children[indx];
    }

    curr->isEnd = 1;
}

void buildSuffixTree(Node* root, char* text)
{
    int n = strlen(text);

    for(int i = 0; i < n; i++)
    {
        insertSuffix(root, text + i);
