#include <stdio.h>
#include <stdlib.h>

#define MAX_POINTS 4

typedef struct Point {
    int x, y;
} Point;

typedef struct QuadTree {
    int x, y, width, height;
    Point* points[MAX_POINTS];
    int count;
    struct QuadTree *nw, *ne, *sw, *se;
} QuadTree;

QuadTree* createQuadTree(int x, int y, int width, int height) {
    QuadTree* qt = (QuadTree*)malloc(sizeof(QuadTree));
    qt->x = x;
    qt->y = y;
    qt->width = width;
    qt->height = height;
    qt->count = 0;
    qt->nw = qt->ne = qt->sw = qt->se = NULL;
    return qt;
}

int contains(QuadTree* qt, Point* p) {
    return (
        p->x >= qt->x &&
        p->x < qt->x + qt->width &&
        p->y >= qt->y &&
        p->y < qt->y + qt->height
    );
}

void subdivide(QuadTree* qt) {
    int halfW = qt->width / 2;
    int halfH = qt->height / 2;

    qt->nw = createQuadTree(qt->x, qt->y, halfW, halfH);

    qt->ne = createQuadTree(
        qt->x + halfW, qt->y, halfW, halfH
    );

    qt->sw = createQuadTree(
        qt->x, qt->y + halfH, halfW, halfH
    );

    qt->se = createQuadTree(
        qt->x + halfW, qt->y + halfH, halfW, halfH
    );
}

void insertIntoChild(QuadTree* qt, Point* p) {

    if (contains(qt->nw, p))
        insert(qt->nw, p);

    else if (contains(qt->ne, p))
        insert(qt->ne, p);

    else if (contains(qt->sw, p))
        insert(qt->sw, p);

    else
        insert(qt->se, p);
}

void insert(QuadTree* qt, Point* p) {

    if (!contains(qt, p))
        return;

    if (qt->count < MAX_POINTS && qt->nw == NULL) {
        qt->points[qt->count++] = p;
        return;
    }

    if (qt->nw == NULL) {

        subdivide(qt);

        for (int i = 0; i < qt->count; i++)
            insertIntoChild(qt, qt->points[i]);

        qt->count = 0;
    }

    insertIntoChild(qt, p);
}

void queryRange(QuadTree* qt,int qx, int qy,int qwidth, int qheight){
    if (qt == NULL)
        return;

    if (qt->x > qx + qwidth ||qt->x + qt->width < qx ||
        qt->y > qy + qheight ||qt->y + qt->height < qy) return;
    for (int i = 0; i < qt->count; i++){

        Point* p = qt->points[i];

        if (p->x >= qx &&
            p->x <= qx + qwidth &&
            p->y >= qy &&
            p->y <= qy + qheight
        ) {
            printf("Point (%d,%d) found\n", p->x, p->y);
        }
    }

    if (qt->nw != NULL) {

        queryRange(qt->nw, qx, qy, qwidth, qheight);
        queryRange(qt->ne, qx, qy, qwidth, qheight);
        queryRange(qt->sw, qx, qy, qwidth, qheight);
        queryRange(qt->se, qx, qy, qwidth, qheight);
    }
}

int main() {

