#include <stdio.h>
#include <stdlib.h>

#define MAX 4

typedef struct Rect {
    int x1, y1, x2, y2;
} Rect;

typedef struct RTreeNode {
    int isLeaf;
    int count;
    Rect mbr;
    Rect rects[MAX];
    struct RTreeNode* children[MAX];

} RTreeNode;

RTreeNode* createNode(int isLeaf) {
    RTreeNode* node = (RTreeNode*)malloc(sizeof(RTreeNode));
    node->isLeaf = isLeaf;
    node->count = 0;
    node->mbr.x1 = 9999;
    node->mbr.y1 = 9999;
    node->mbr.x2 = -9999;
    node->mbr.y2 = -9999;
    for(int i=0;i<MAX;i++)
        node->children[i] = NULL;

    return node;
}

void updateMBR(RTreeNode* node, Rect r) {
    if(r.x1 < node->mbr.x1)
        node->mbr.x1 = r.x1;

    if(r.y1 < node->mbr.y1)
        node->mbr.y1 = r.y1;

    if(r.x2 > node->mbr.x2)
        node->mbr.x2 = r.x2;

    if(r.y2 > node->mbr.y2)
        node->mbr.y2 = r.y2;
}

void calculateMBR(RTreeNode* node) {

    node->mbr.x1 = 9999;
    node->mbr.y1 = 9999;
    node->mbr.x2 = -9999;
    node->mbr.y2 = -9999;
    for(int i=0;i<node->count;i++) {
        updateMBR(node, node->rects[i]);
    }
}

RTreeNode* splitNode(RTreeNode* node) {
    RTreeNode* newNode = createNode(node->isLeaf);
    int mid = MAX / 2;
    for(int i=mid;i<MAX;i++) {
        newNode->rects[newNode->count] = node->rects[i];
        newNode->children[newNode->count] = node->children[i];
        newNode->count++;
    }
    node->count = mid;
    calculateMBR(node);
    calculateMBR(newNode);
    return newNode;
}

RTreeNode* insertRect(RTreeNode* root, Rect r) {
    if(root->count < MAX) {
        root->rects[root->count++] = r;
        updateMBR(root, r);
        return NULL;
    }

    else {
        printf("Node Full -> Splitting...\n");
        RTreeNode* newNode = splitNode(root);
        newNode->rects[newNode->count] = r;
        newNode->count++;
        updateMBR(newNode, r);
        return newNode;
    }
}

int intersects(Rect a, Rect b) {
    return !(a.x2 < b.x1 || a.x1 > b.x2 ||
             a.y2 < b.y1 || a.y1 > b.y2);
}

void searchRTree(RTreeNode* root, Rect query) {
    if(root == NULL)
        return;
    if(!intersects(root->mbr, query))
        return;
    for(int i=0;i<root->count;i++) {
        if(intersects(root->rects[i], query)) {
            printf("Intersecting Rectangle: ");
            printf("(%d,%d)-(%d,%d)\n",
                   root->rects[i].x1,
                   root->rects[i].y1,
                   root->rects[i].x2,
                   root->rects[i].y2);
        }
    }
}

int main() {
    RTreeNode* root = createNode(1);
    RTreeNode* splitPart = NULL;
    Rect r1 = {1,1,3,3};
    Rect r2 = {2,2,5,5};
    Rect r3 = {6,6,8,8};
    Rect r4 = {0,0,2,2};
    Rect r5 = {7,1,9,4};
    insertRect(root, r1);
    insertRect(root, r2);
    insertRect(root, r3);
    insertRect(root, r4);

    splitPart = insertRect(root, r5);
    Rect query = {2,2,6,6};
    printf("\nSearching Query (%d,%d)-(%d,%d)\n",
           query.x1, query.y1,
           query.x2, query.y2);

    searchRTree(root, query);
    if(splitPart != NULL)
        searchRTree(splitPart, query);
    return 0;
}
